//------------------------Instantiation------------------
    generate 
    if (NUM_PORTS > 2) begin
        LINEAR_BLOCK_in_r_m_axi_fifo #(
            .DATA_WIDTH        (PACK_WIDTH),
            .ADDR_WIDTH        (log2(NUM_PORTS)),
            .DEPTH             (NUM_PORTS)
        ) req_buffer (
            .clk               (clk),
